import type { Language } from "./i18n";

export type ExamType = "bcs" | "medical" | "engineering" | "university" | "ssc" | "hsc" | "jsc" | "psc" | "madrasah";
export type Difficulty = "easy" | "medium" | "hard";
export type PracticeMode = "relaxed" | "timed" | "speed" | "marathon";

export type BloomLevel = "remember" | "understand" | "apply" | "analyze" | "evaluate" | "create";

export interface Question {
  id: string;
  examType: ExamType;
  subject: string;
  topic: string;
  difficulty: Difficulty;
  question: string;
  options: string[];
  correctAnswer: number;
  explanation: string;
  language: Language;
  estimated_time?: number;
  bloom_taxonomy_level?: BloomLevel;
  year_appeared?: number;
}

export interface SubjectInfo {
  id: string;
  name: string;
  nameBn: string;
  icon: string;
  color: string;
  topics: string[];
  topicsBn: string[];
}

export interface ExamTypeInfo {
  id: ExamType;
  name: string;
  nameBn: string;
  icon: string;
  description: string;
  descriptionBn: string;
  category: "competitive" | "board";
  subjects: SubjectInfo[];
}

export interface ExamConfig {
  subject: string;
  topic?: string;
  difficulty?: Difficulty;
  count: number;
  timePerQuestion: number;
  questions: Question[];
  adaptive?: boolean;
  practiceMode?: PracticeMode;
}

export interface ExamAnswer {
  questionId: string;
  selectedOption: number | null;
  timeSpent: number;
  markedForReview: boolean;
}

export interface ExamResult {
  id: string;
  date: string;
  subject: string;
  topic?: string;
  totalQuestions: number;
  correctAnswers: number;
  wrongAnswers: number;
  skipped: number;
  totalTime: number;
  answers: ExamAnswer[];
  questions: Question[];
  score: number;
  adaptive?: boolean;
  difficultyProgression?: Difficulty[];
  practiceMode?: PracticeMode;
}

export interface SubjectProgress {
  total: number;
  correct: number;
}

export interface TopicProgress {
  total: number;
  correct: number;
  lastPracticed: string;
  consecutiveCorrect: number;
}

export interface UserData {
  examType: ExamType;
  streak: number;
  lastPracticeDate: string;
  totalQuestionsSolved: number;
  totalCorrect: number;
  subjectProgress: Record<string, SubjectProgress>;
  topicProgress: Record<string, TopicProgress>;
  examHistory: ExamResult[];
  onboarded: boolean;
  xp: number;
  language: Language;
}

